// Extract company information from Google search results
const items = $input.item.json.items || [];
const companies = [];

for (const item of items) {
  const title = item.title || '';
  const snippet = item.snippet || '';
  const link = item.link || '';

  // Extract domain from URL
  let domain = '';
  try {
    const url = new URL(link);
    domain = url.hostname.replace('www.', '');
  } catch (e) {
    domain = link;
  }

  // Skip non-company results
  if (domain.includes('linkedin.com') || 
      domain.includes('facebook.com') || 
      domain.includes('wikipedia.org') ||
      domain.includes('youtube.com')) {
    continue;
  }

  // Extract company name from title
  let companyName = title.split('|')[0].split('-')[0].trim();

  companies.push({
    companyName: companyName,
    domain: domain,
    website: link,
    description: snippet,
    searchQuery: $input.item.json.searchQuery,
    location: $input.item.json.location,
    hunterApiKey: $input.item.json.hunterApiKey
  });
}

return companies.map(company => ({ json: company }));

// Combine Hunter.io emails with scraped data
const hunterData = $input.first().json.data || {};
const websiteData = $input.last().json.data || '';
const companyInfo = $input.first().json;

// Extract Hunter.io emails
const hunterEmails = hunterData.emails || [];
const decisionMakers = hunterEmails
  .filter(e => e.value && e.confidence > 50)
  .map(e => ({
    email: e.value,
    firstName: e.first_name,
    lastName: e.last_name,
    fullName: `${e.first_name} ${e.last_name}`,
    position: e.position || 'Unknown',
    department: e.department,
    seniority: e.seniority,
    confidence: e.confidence,
    verified: e.verification?.status === 'valid',
    source: 'Hunter.io'
  }));

// Extract additional emails from website HTML
const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/gi;
const scrapedEmails = (websiteData.match(emailRegex) || [])
  .filter(email => {
    const lower = email.toLowerCase();
    return email.includes(companyInfo.domain.split('.')[0]) &&
           !lower.includes('example') &&
           !lower.includes('test') &&
           email.length < 100;
  });

// Remove duplicates
const uniqueScraped = [...new Set(scrapedEmails)]
  .filter(email => !hunterEmails.some(h => h.value === email))
  .slice(0, 5);

// Extract phone numbers from website
const phoneRegex = /(?:\+\d{1,3}[-.\s]?)?(?:\(?\d{1,4}\)?[-.\s]?)?\d{1,4}[-.\s]?\d{1,4}[-.\s]?\d{1,9}/g;
const phones = (websiteData.match(phoneRegex) || [])
  .filter(p => p.length >= 10 && p.length <= 20)
  .slice(0, 3);

// Categorize emails
const genericPatterns = /^(info|contact|hello|support|sales|admin|inquiry|service|help)@/i;
const allEmails = [...hunterEmails.map(e => e.value), ...uniqueScraped];
const genericEmails = allEmails.filter(e => genericPatterns.test(e));
const personalEmails = allEmails.filter(e => !genericPatterns.test(e));

// Categorize decision makers by seniority
const executives = decisionMakers.filter(dm => 
  dm.seniority === 'executive' || 
  dm.position?.match(/CEO|Founder|President|Owner|Chief/i)
);

const directors = decisionMakers.filter(dm => 
  dm.seniority === 'director' ||
  dm.position?.match(/Director|VP|Vice President/i)
);

const managers = decisionMakers.filter(dm => 
  dm.seniority === 'manager' ||
  dm.position?.match(/Manager|Head of|Lead/i)
);

return {
  // Company Info
  companyName: companyInfo.companyName,
  domain: companyInfo.domain,
  website: companyInfo.website,
  description: companyInfo.description,
  location: companyInfo.location,

  // Contact Info
  phones: phones,
  primaryPhone: phones[0] || 'Not found',

  // Email Data
  allEmails: allEmails,
  genericEmails: genericEmails,
  personalEmails: personalEmails,
  scrapedEmails: uniqueScraped,

  // Decision Makers
  decisionMakers: decisionMakers,
  executives: executives,
  directors: directors,
  managers: managers,

  // Stats
  totalContacts: decisionMakers.length,
  totalEmails: allEmails.length,
  verifiedEmails: decisionMakers.filter(dm => dm.verified).length,
  hunterCreditsUsed: 1,

  // Organization
  organization: hunterData.organization || companyInfo.companyName,
  pattern: hunterData.pattern || 'Unknown',

  // Metadata
  source: 'Google Search + Hunter.io + Web Scraping',
  timestamp: new Date().toISOString()
};

// Add Clearbit enrichment data
const mainData = $input.first().json;
const clearbitData = $input.last().json;

// Extract Clearbit info if available
let enrichedData = { ...mainData };

if (clearbitData && !clearbitData.error) {
  enrichedData = {
    ...mainData,
    industry: clearbitData.category?.industry || mainData.industry,
    subIndustry: clearbitData.category?.subIndustry,
    employeeCount: clearbitData.metrics?.employees || 'Unknown',
    employeeRange: clearbitData.metrics?.employeesRange,
    foundedYear: clearbitData.foundedYear,
    revenue: clearbitData.metrics?.estimatedAnnualRevenue,
    revenueRange: clearbitData.metrics?.annualRevenue,
    techStack: clearbitData.tech || [],
    description: clearbitData.description || mainData.description,
    logo: clearbitData.logo,
    linkedin: clearbitData.linkedin?.handle,
    twitter: clearbitData.twitter?.handle,
    facebook: clearbitData.facebook?.handle,
    clearbitEnriched: true
  };
} else {
  enrichedData.clearbitEnriched = false;
}

return enrichedData;

// Generate campaign statistics
const items = $input.all();

const totalCompanies = items.length;
const withEmails = items.filter(i => (i.json.totalEmails || 0) > 0).length;
const totalContacts = items.reduce((sum, i) => sum + (i.json.totalContacts || 0), 0);
const totalEmails = items.reduce((sum, i) => sum + (i.json.totalEmails || 0), 0);
const verifiedEmails = items.reduce((sum, i) => sum + (i.json.verifiedEmails || 0), 0);
const hunterCredits = items.reduce((sum, i) => sum + (i.json.hunterCreditsUsed || 0), 0);
const clearbitUsed = items.filter(i => i.json.clearbitEnriched).length;

// Calculate cost savings vs Apollo
const apolloCostPerContact = 0.15; // Apollo charges ~$0.15 per contact
const savedAmount = totalContacts * apolloCostPerContact;

return {
  summary: {
    totalCompaniesSearched: totalCompanies,
    companiesWithEmails: withEmails,
    successRate: ((withEmails / totalCompanies) * 100).toFixed(1) + '%',

    totalContactsFound: totalContacts,
    totalEmailsFound: totalEmails,
    verifiedEmails: verifiedEmails,
    verificationRate: totalEmails > 0 ? ((verifiedEmails / totalEmails) * 100).toFixed(1) + '%' : '0%',

    averageContactsPerCompany: (totalContacts / totalCompanies).toFixed(2),
    averageEmailsPerCompany: (totalEmails / totalCompanies).toFixed(2),

    // API Usage
    googleSearchesUsed: 1,
    hunterCreditsUsed: hunterCredits,
    clearbitRequestsUsed: clearbitUsed,

    // Limits
    googleSearchesRemaining: 99, // 100 per day
    hunterCreditsRemaining: 25 - hunterCredits, // 25 per month
    clearbitRequestsRemaining: 50 - clearbitUsed, // 50 per month

    // Cost Comparison
    apolloEquivalentCost: '$' + savedAmount.toFixed(2),
    actualCost: '$0.00 (FREE)',
    moneySaved: '$' + savedAmount.toFixed(2),

    timestamp: new Date().toISOString(),

    recommendation: hunterCredits > 20 ? 
      '⚠️ Hunter.io credits running low. Consider slowing down searches.' : 
      '✅ All systems go! You have plenty of free credits remaining.'
  }
};
